from flask import Flask, send_file, abort
import os

app = Flask(__name__)

INVOICE_DIRECTORY = '/path/to/invoices'

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    invoice_filename = f"invoice_{invoice_id}.pdf"
    invoice_path = os.path.join(INVOICE_DIRECTORY, invoice_filename)

    if not os.path.isfile(invoice_path):
        abort(404, description="Invoice not found")

    try:
        return send_file(invoice_path, as_attachment=True)
    except Exception as e:
        abort(500, description="Error downloading the invoice")

if __name__ == '__main__':
    app.run(debug=False)